import re
from pathlib import Path
from collections import defaultdict

SOURCES = [
    "competitor_a.md", "competitor_b.md",
    "market_report.md", "press_releases.md"
]

SOURCE_TAG = re.compile(r'\[source: ([^,\]]+)')

def assemble_packet(source_files: list[str]) -> dict:
    all_claims = []
    source_index = defaultdict(int)
    conflicts = []
    claim_map = {}  # key -> (value, source)

    for src in source_files:
        content = Path(src).read_text()
        for line in content.splitlines():
            tags = SOURCE_TAG.findall(line)
            for tag in tags:
                source_index[tag.strip()] += 1
                # Conflict detection: same claim key, different value
                key = line.split('[source:')[0].strip()[:60]
                if key in claim_map and claim_map[key][1] != tag:
                    conflicts.append({"claim": key, "source1": claim_map[key][1],
                                      "source2": tag})
                else:
                    claim_map[key] = (line, tag)
            all_claims.append(line)

    return {"claims": all_claims, "source_index": dict(source_index),
            "conflicts": conflicts}
